"use strict";(()=>{(function(){"use strict";document.addEventListener("DOMContentLoaded",()=>{if(typeof gsap>"u"||typeof ScrollTrigger>"u"){console.warn("[animations] GSAP or ScrollTrigger not loaded \u2014 ensure Webflow GSAP toggle is enabled");return}gsap.registerPlugin(ScrollTrigger),document.querySelectorAll("[data-animation-general]").forEach(e=>{gsap.from(e,{opacity:0,y:30,duration:.8,ease:"power2.out",scrollTrigger:{trigger:e,start:"top 85%",toggleActions:"play none none none"}})})})})();})();
